const f = (x) => 0.2 * Math.pow(x, 3) - Math.pow(x, 2) + x + 4;
const start = 0;
const end = 5;
const steps = 100;
const nRects = 12;
const dx = (end - start) / nRects;

// 1. Generate the continuous function curve
const xCurve = [];
const yCurve = [];
for (let i = 0; i <= steps; i++) {
  const x = start + (i * (end - start + 1)) / steps;
  xCurve.push(x);
  yCurve.push(f(x));
}

// 2. Generate Riemann Rectangles (Left Sum)
const xRects = [];
const yRects = [];
for (let i = 0; i < nRects; i++) {
  const x0 = start + i * dx;
  const x1 = x0 + dx;
  const y = f(x0);
  // Create rectangular paths for scatter fill or use bar trace
  // Using bar trace for better visual separation
  xRects.push(x0 + dx/2);
  yRects.push(y);
}

// 3. Exact Area Shading
const xArea = [];
const yArea = [];
for (let i = 0; i <= steps; i++) {
  const x = start + (i * (end - start)) / steps;
  xArea.push(x);
  yArea.push(f(x));
}

return [
  {
    x: xArea,
    y: yArea,
    type: 'scatter',
    mode: 'lines',
    name: 'Exact Area',
    fill: 'tozeroy',
    fillcolor: 'rgba(16, 185, 129, 0.2)',
    line: { color: 'transparent' },
    hoverinfo: 'skip'
  },
  {
    x: xRects,
    y: yRects,
    type: 'bar',
    name: 'Riemann Sum (n=12)',
    marker: {
      color: 'rgba(59, 130, 246, 0.5)',
      line: { color: '#3b82f6', width: 1 }
    },
    width: dx,
    offset: -dx/2
  },
  {
    x: xCurve,
    y: yCurve,
    type: 'scatter',
    mode: 'lines',
    name: 'f(x)',
    line: { color: '#f8fafc', width: 3 }
  }
];
